1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
21	type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
22	type Step = { op: "quote"; items: Item[] };
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
26	
27	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
28	
29	const isMainItem = (item: Item): boolean => !isComponent(item);
30	
31	const groupByType = (items: Item[]): Map<string, number> =>
32	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
33	
34	const componentGroupPremium = (type: string, count: number): number =>
35	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
36	
37	const componentsPremium = (items: Item[]): number =>
38	  Array.from(groupByType(items.filter(isComponent)))
39	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
40	
41	const isHighlyEnchanted = (item: Item): boolean =>
42	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
43	
44	const surchargeWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
45	
46	const itemSurcharge = (item: Item): number =>
47	  surchargeWhen(item.cursed === true, CURSED_SURCHARGE) +
48	  surchargeWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
49	
50	const itemPremium = (item: Item): number =>
51	  basePremiumFor(item.type) * (1 + itemSurcharge(item));
52	
53	const mainItemsPremium = (items: Item[]): number =>
54	  items.filter(isMainItem)
55	    .reduce((sum, item) => sum + itemPremium(item), 0);
56	
57	const itemsPremium = (items: Item[]): number =>
58	  mainItemsPremium(items) + componentsPremium(items);
59	
60	const policySurcharge = (customer: Customer): number =>
61	  surchargeWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE);
62	
63	const FLOATING_POINT_EPSILON = 1e-9;
64	
65	const roundUpInOurFavor = (amount: number): number =>
66	  Math.ceil(amount - FLOATING_POINT_EPSILON);
67	
68	const quote = (customer: Customer) => ({ items }: Step): { premium: number } => ({
69	  premium: roundUpInOurFavor(itemsPremium(items) * (1 + policySurcharge(customer)) + PROCESSING_FEE),
70	});
71	
72	export const runScenario = (input: unknown): unknown => {
73	  const { customer, steps } = input as Scenario;
74	  return { results: steps.map(quote(customer)) };
75	};
