const surchargeWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);

const applySurcharge = (base: number, rate: number): number => base * (1 + rate);

const itemSurcharge = (item: Item): number =>
  surchargeWhen(item.cursed === true, CURSED_SURCHARGE) +
  surchargeWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);

const itemPremium = (item: Item): number =>
  applySurcharge(basePremiumFor(item.type), itemSurcharge(item));

const mainItemsPremium = (items: Item[]): number =>
  items.filter(isMainItem)
    .reduce((sum, item) => sum + itemPremium(item), 0);

const itemsPremium = (items: Item[]): number =>
  mainItemsPremium(items) + componentsPremium(items);

const policySurcharge = (customer: Customer): number =>
  surchargeWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE);

const FLOATING_POINT_EPSILON = 1e-9;

const roundUpInOurFavor = (amount: number): number =>
  Math.ceil(amount - FLOATING_POINT_EPSILON);

const quote = (customer: Customer) => ({ items }: Step): { premium: number } => ({
  premium: roundUpInOurFavor(applySurcharge(itemsPremium(items), policySurcharge(customer)) + PROCESSING_FEE),
});
